getNominationsByAwardId:
SELECT id, * FROM "Nomination" n
WHERE n."tenantId" = '{{tenantCode}}' AND n."awardId" IN ('{{awardId}}')
ORDER BY id DESC;

getNominationInstancesByNominationId:
SELECT * FROM "NominationInstance" ni
WHERE ni."tenantId" = '{{tenantCode}}' AND ni."nominationId" = '{{nominationId}}'
ORDER BY ni."id" DESC;
